int orientation(pair<int,int> a, pair<int,int> b, pair<int,int> c) {
    long long cross = (b.first - a.first) * (c.second - a.second)
                    - (b.second - a.second) * (c.first - a.first);
    if (cross > 0) return 1;   // CW
    if (cross < 0) return -1;  // CCW
    return 0;                   // collinear
}

