def count_parallelograms(points):
    mid_counts = {}
    n = len(points)
    for i in range(n):
        for j in range(i+1, n):
            mx = points[i][0] + points[j][0]  # store 2x to avoid fractions
            my = points[i][1] + points[j][1]
            mid_counts[(mx, my)] = mid_counts.get((mx, my), 0) + 1

    ans = 0
    for k in mid_counts.values():
        ans += k * (k - 1) // 2
    return ans

long long countParallelograms(vector<pair<int,int>>& points) {
    map<pair<int,int>, long long> midCounts;
    int n = points.size();
    for (int i = 0; i < n; i++)
        for (int j = i+1; j < n; j++) {
            int mx = points[i].first + points[j].first;
            int my = points[i].second + points[j].second;
            midCounts[{mx, my}]++;
        }
    long long ans = 0;
    for (auto& [_, k] : midCounts) ans += k * (k - 1) / 2;
    return ans;
}

